patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 0200525a718d..21ca90ede2fe 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7315,7 +7315,13 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      if (!SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true))
+        return true;
+      // Check if the instruction involves constants, which may cause
+      // cost model discrepancies.
+      if (any_of(I.operands(), [](const Value *V) { return isa<Constant>(V); }))
+        return true;
+      return false;
     });
   });
 }

