diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 0200525a718d..e6064d5ae2e3 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7312,6 +7312,15 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
+  // Check if any instruction in the loop involves constants.
+  // Constant instructions may be costed differently between the two models.
+  if (any_of(TheLoop->blocks(), [](BasicBlock *BB) {
+        return any_of(*BB, [](Instruction &I) {
+          return (I.isBinaryOp() || I.isUnaryOp() || isa<CmpInst>(&I) || isa<CastInst>(&I)) &&
+                 any_of(I.operands(), [](const Value *V) { return isa<Constant>(V); });
+        });
+      }))
+    return true;
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 0200525a718d..08821e35c68d 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7311,13 +7311,17 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
-      if (isa<PHINode>(&I))
-        return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
-    });
   });
+  // Check if any instruction in the loop involves constants, which may cause
+  // cost model discrepancies.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      if (isa<PHINode>(&I))
+        continue;
+      if (any_of(I.operands(), [](const Value *V) { return isa<Constant>(V); }))
+        return true;
+    }
+  }
 }
 #endif

